import React, { useEffect, useRef, useState } from 'react';
import styles from './index.module.scss';
import PageBg from '../components/page-bg/page-bg';
import Popup from '../components/popup/popup';
import imga from '../images/icon01.png';
import textWscs from '../images/text-wscs.png';
import icona from '../images/item01a.png';
import iconb from '../images/item01b.png';
import iconc from '../images/item01c.png';
import arrd01 from '../images/arr-d01.png';
import SelectPop from '../components/select-pop/select-pop';

const optionsa = [
  { value: 1, label: '食品从业人员'},
  { value: 2, label: '在校学生'},
  { value: 3, label: '普通市民'},
];
const optionsb = [
  { value: 1, label: '18岁以下'},
  { value: 2, label: '18-25岁以下'},
  { value: 3, label: '26-40岁以下'},
  { value: 4, label: '41-60岁以下'},
  { value: 5, label: '60岁以上'},
];

const optionsc = [
  { value: 1, label: '浦东新区'},
  { value: 2, label: '徐汇区'},
  { value: 3, label: '杨浦区'},
  { value: 4, label: '长宁区'},
  { value: 5, label: '静安区'},
];

function App(props) {
  const selectedRef = useRef({});
  const dataRef = useState({});
  const [open, setOpen] = useState(false);
  const [selected, setSelected] = useState({});
  const [opena, setOpena] = useState(false);
  const [quLabel, setQuLabel] = useState('')

  // 选择
  const onOptionSelect = (type, value) => {
    selectedRef.current[type] = value;
    setSelected({ ...selectedRef.current });
  };

  const onSelectOk = (val, node) => {
    selectedRef.current.qu = val;
    setOpena(false);
    setSelected({ ...selectedRef.current });
    setQuLabel(node.label);
  };
  useEffect(() => {
  }, [])
  return (
    <PageBg className={styles['a']}>
      <div onClick={() => setOpen(true)} style={{ padding: 30}}>测试打开</div>
      <Popup
        open={open}
        className={styles['info-popup']}
      >
        <div className={styles['bar']}>
          <img src={imga} className={styles['bar-icon']} />
          <img src={textWscs} className={styles['bar-text-wscs']} />
        </div>
        <div className={styles['form']}>
          <div className={styles['form-inner']}>
              <div className={styles['wrap']}>
                <div className={`flex ${styles['wrap-top']}`}>
                  <div className={styles['wrap-til']}>完善参赛信息</div>
                  <div className={`flex-aic-jcc ${styles['wrap-icon']}`}><img src={icona} className={styles['icona']} /></div>
                </div>
                <div className={`flex-aic-jcsb ${styles['wrap-cont']} ${styles['select']}`} onClick={() => setOpena(true)}>
                  <div>{quLabel || '请选择所在区'}</div>
                  <img src={arrd01} className={styles['wrap-arrd']} />
                </div>
              </div>

              <div className={styles['wrap']}>
                <div className={`flex ${styles['wrap-top']}`}>
                  <div className={styles['wrap-til']}>身份属性</div>
                  <div className={`flex-aic-jcc ${styles['wrap-icon']}`}><img src={iconb} className={styles['iconb']} /></div>
                </div>
                <div className={`flex-aic-jcsb ${styles['wrap-cont']}`}>
                  {optionsa.map(item => (
                    <div
                      key={item.value}
                      className={`${styles['wrap-option']} ${selected.attr === item.value ? styles['active'] : ''}`}
                      onClick={() => onOptionSelect('attr', item.value)}
                    >
                      {item.label}
                    </div>
                  ))}
                </div>
              </div>

              <div className={styles['wrap']}>
                <div className={`flex ${styles['wrap-top']}`}>
                  <div className={styles['wrap-til']}>年龄段</div>
                  <div className={`flex-aic-jcc ${styles['wrap-icon']}`}><img src={iconc} className={styles['iconc']} /></div>
                </div>
                <div className={`flex-aic-jcsb ${styles['wrap-cont']} ${styles['line']}`}>
                  {optionsb.map((item, index) => (
                    <div
                      key={item.value}
                      className={`${styles['wrap-option']} ${index === optionsb.length - 1 ? styles['full'] : ''} ${selected.age === item.value ? styles['active'] : ''}`}
                      onClick={() => onOptionSelect('age', item.value)}
                    >
                      {item.label}
                    </div>
                  ))}
                </div>
              </div>
          </div>
          <div className={styles['form-btn']} onClick={() => setOpen(false)}>确认提交</div>
        </div>
      </Popup>
      <SelectPop
        open={opena}
        options={optionsc}
        onCancel={() => setOpena(false)}
        onChange={onSelectOk}
        dynamicValue={selected.qu}
      />
    </PageBg>
  );
}

export default React.memo(App);
